import { useState, useEffect, useCallback, useRef } from 'react';
import './LensShowcase.css';

const API = process.env.REACT_APP_LENS_API_URL || 'https://lens-api-cpktdw5swq-uc.a.run.app';

// Seeded LCG for deterministic background graph positions
function seeded(seed) {
  let s = seed;
  return () => { s = Math.imul(s, 1664525) + 1013904223 | 0; return (s >>> 0) / 0xffffffff; };
}
const _r = seeded(137);
const GRAPH_NODES = Array.from({ length: 55 }, () => ({ x: _r() * 100, y: _r() * 100, r: 0.35 + _r() * 0.55 }));
const GRAPH_EDGES = GRAPH_NODES.flatMap((a, i) =>
  GRAPH_NODES.slice(i + 1).flatMap((b, j) => {
    const dx = a.x - b.x, dy = a.y - b.y;
    return dx * dx + dy * dy < 280 ? [[i, i + 1 + j]] : [];
  })
);

const MODELS = [
  { id: 'local',  name: 'all-MiniLM-L6-v2',       detail: 'Runs in the backend container — no setup needed', badge: 'free',  badgeLabel: 'Free' },
  { id: 'openai', name: 'text-embedding-3-small',   detail: 'OpenAI API — best retrieval quality',             badge: 'api',   badgeLabel: 'API Key' },
  { id: 'ollama', name: 'nomic-embed-text',          detail: 'Self-hosted Ollama — local backend only',         badge: 'local', badgeLabel: 'Self-hosted' },
];

const DEMO_REPOS = [
  { label: 'Lens API (indexed)', url: 'https://github.com/adsouza5/lens-api' },
  { label: 'Prism API',          url: 'https://github.com/adsouza5/prism-api' },
  { label: 'Sentinel ML',        url: 'https://github.com/adsouza5/sentinel-ml-pipeline' },
  { label: 'FastAPI',            url: 'https://github.com/fastapi/fastapi' },
  { label: 'Qdrant',             url: 'https://github.com/qdrant/qdrant' },
];

const SAMPLE_QUERIES = [
  'where is rate limiting implemented',
  'how are embeddings generated',
  'find the vector search logic',
  'API route definitions',
  'error handling patterns',
  'how is the repo cloned and parsed',
];

const PIPELINE_STEPS = [
  { label: 'GitHub Repo',    sub: 'URL input' },
  { label: 'Clone & Walk',   sub: 'git + file scan' },
  { label: 'AST Chunks',     sub: 'tree-sitter · fn/class' },
  { label: 'Embed',          sub: 'jina · OpenAI · Ollama' },
  { label: 'Qdrant',         sub: 'vector similarity' },
  { label: 'Results',        sub: 'file · line · score' },
];

const REPO_STORAGE_KEY = 'lens_collection_repos';

const SEEDED_REPO_MAP = {
  'lens-https-github-com-adsouza5-lens-api':              'https://github.com/adsouza5/lens-api',
  'lens-https-github-com-adsouza5-prism-api':             'https://github.com/adsouza5/prism-api',
  'lens-https-github-com-adsouza5-sentinel-ml-pipeline':  'https://github.com/adsouza5/sentinel-ml-pipeline',
};

function loadRepoMap() {
  try { return { ...SEEDED_REPO_MAP, ...JSON.parse(localStorage.getItem(REPO_STORAGE_KEY) || '{}') }; }
  catch { return { ...SEEDED_REPO_MAP }; }
}
function saveRepoMap(map) {
  try { localStorage.setItem(REPO_STORAGE_KEY, JSON.stringify(map)); } catch {}
}
function githubFileUrl(repoUrl, filePath, startLine, endLine) {
  if (!repoUrl) return null;
  return `${repoUrl.replace(/\.git$/, '').replace(/\/$/, '')}/blob/main/${filePath}#L${startLine}-L${endLine}`;
}

const LANGUAGES = ['python', 'javascript', 'typescript', 'go', 'rust', 'java'];

// ── Sub-components ────────────────────────────────────────────

function ModelSelector({ selected, onChange }) {
  return (
    <div className="lens-model-grid">
      {MODELS.map(m => (
        <button key={m.id} className={`lens-model-option${selected === m.id ? ' selected' : ''}`} onClick={() => onChange(m.id)}>
          <div className="lens-model-name">{m.name}</div>
          <div className="lens-model-detail">{m.detail}</div>
          <span className={`lens-model-badge ${m.badge}`}>{m.badgeLabel}</span>
        </button>
      ))}
    </div>
  );
}

function ProgressView({ events }) {
  const last = events[events.length - 1];
  if (!last) return null;
  const filesTotal  = last.files_total  ?? 0;
  const filesDone   = last.files_done   ?? 0;
  const chunksTotal = last.chunks_total ?? 0;
  const chunksDone  = last.chunks_done  ?? 0;
  const pct = chunksTotal > 0
    ? Math.round((chunksDone / chunksTotal) * 100)
    : filesTotal > 0 ? Math.round((filesDone / filesTotal) * 100) : 0;
  if (last.type === 'done')  return <div className="lens-done-banner">✓ Indexed {last.chunks} chunks from {last.files} files · {last.provider}</div>;
  if (last.type === 'error') return <div className="lens-error-banner">✕ {last.message}</div>;
  return (
    <div className="lens-progress-wrap">
      <div className="lens-progress-msg"><div className="lens-spinner" />{last.message}</div>
      {pct > 0 && (
        <>
          <div className="lens-progress-bar-track"><div className="lens-progress-bar-fill" style={{ width: `${pct}%` }} /></div>
          <div className="lens-progress-stats">
            {filesTotal  > 0 && <span>{filesDone}/{filesTotal} files</span>}
            {chunksTotal > 0 && <span>{chunksDone}/{chunksTotal} chunks</span>}
            <span>{pct}%</span>
          </div>
        </>
      )}
    </div>
  );
}

function LangSelect({ value, onChange }) {
  const [open, setOpen]       = useState(false);
  const [menuPos, setMenuPos] = useState({ top: 0, left: 0, width: 0 });
  const btnRef  = useRef(null);
  const wrapRef = useRef(null);
  useEffect(() => {
    const h = e => { if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);
  const MENU_HEIGHT = (LANGUAGES.length + 1) * 38;
  function toggle() {
    if (!open && btnRef.current) {
      const r = btnRef.current.getBoundingClientRect();
      const spaceBelow = window.innerHeight - r.bottom;
      const top = spaceBelow >= MENU_HEIGHT + 8 ? r.bottom + 5 : r.top - MENU_HEIGHT - 5;
      setMenuPos({ top, left: r.left, width: r.width });
    }
    setOpen(o => !o);
  }
  return (
    <div className="lens-lang-wrap" ref={wrapRef}>
      <button ref={btnRef} className={`lens-lang-btn${open ? ' open' : ''}`} onClick={toggle} type="button">
        <span>{value || 'All langs'}</span>
        <span className="lens-lang-chevron">{open ? '▲' : '▼'}</span>
      </button>
      {open && (
        <div className="lens-lang-menu" style={{ position: 'fixed', top: menuPos.top, left: menuPos.left, minWidth: menuPos.width }}>
          <button className={`lens-lang-item${!value ? ' active' : ''}`} onClick={() => { onChange(''); setOpen(false); }}>All languages</button>
          {LANGUAGES.map(l => (
            <button key={l} className={`lens-lang-item${value === l ? ' active' : ''}`} onClick={() => { onChange(l); setOpen(false); }}>{l}</button>
          ))}
        </div>
      )}
    </div>
  );
}

function CopyButton({ text }) {
  const [copied, setCopied] = useState(false);
  const copy = () => { navigator.clipboard.writeText(text).then(() => { setCopied(true); setTimeout(() => setCopied(false), 1500); }); };
  return <button className="lens-copy-btn" onClick={copy} title="Copy">{copied ? '✓' : '⎘'}</button>;
}

function ResultModal({ result, repoUrl, onClose }) {
  const ghUrl = githubFileUrl(repoUrl, result.file_path, result.start_line, result.end_line);
  useEffect(() => {
    const onKey = e => e.key === 'Escape' && onClose();
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [onClose]);
  return (
    <div className="lens-modal-backdrop" onClick={onClose}>
      <div className="lens-modal" onClick={e => e.stopPropagation()}>
        <div className="lens-modal-header">
          <div className="lens-modal-meta">
            {ghUrl
              ? <a className="lens-result-filepath" href={ghUrl} target="_blank" rel="noopener noreferrer">{result.file_path}</a>
              : <span className="lens-result-filepath">{result.file_path}</span>}
            {result.symbol && <span className="lens-result-symbol">{result.symbol}</span>}
            <span className="lens-result-lines">L{result.start_line}–{result.end_line}</span>
            <span className="lens-result-score">{(result.score * 100).toFixed(1)}%</span>
          </div>
          <div className="lens-modal-actions">
            <CopyButton text={result.content} />
            <button className="lens-modal-close" onClick={onClose} title="Close">✕</button>
          </div>
        </div>
        <pre className="lens-modal-code">{result.content}</pre>
      </div>
    </div>
  );
}

function ResultCard({ result, index, repoUrl, onExpand }) {
  const ghUrl = githubFileUrl(repoUrl, result.file_path, result.start_line, result.end_line);
  const scoreVal = result.score * 100;
  const scoreColor = scoreVal >= 80 ? '#34d399' : scoreVal >= 60 ? '#1aacbe' : 'rgba(232,232,232,0.55)';
  return (
    <div className="lens-result-card" style={{ animationDelay: `${index * 0.05}s` }}>
      <div className="lens-result-meta">
        {ghUrl
          ? <a className="lens-result-filepath" href={ghUrl} target="_blank" rel="noopener noreferrer">{result.file_path}</a>
          : <span className="lens-result-filepath">{result.file_path}</span>}
        {result.symbol && <span className="lens-result-symbol">{result.symbol}</span>}
        <span className="lens-result-lines">L{result.start_line}–{result.end_line}</span>
        <span className="lens-result-score" style={{ color: scoreColor }}>{scoreVal.toFixed(1)}%</span>
        <CopyButton text={result.content} />
        <button className="lens-expand-btn" onClick={() => onExpand(result)} title="Expand">⤢</button>
      </div>
      <pre className="lens-result-code">{result.content}</pre>
    </div>
  );
}

function Pipeline() {
  return (
    <div className="lens-pipeline" aria-hidden="true">
      {PIPELINE_STEPS.map((step, i) => (
        <div key={step.label} className="lens-pipeline-item">
          <div className="lens-pipeline-node">
            <div className="lens-pipeline-label">{step.label}</div>
            <div className="lens-pipeline-sub">{step.sub}</div>
          </div>
          {i < PIPELINE_STEPS.length - 1 && (
            <div className="lens-pipeline-arrow">
              <svg width="28" height="10" viewBox="0 0 28 10" fill="none">
                <line x1="0" y1="5" x2="22" y2="5" stroke="rgba(23,126,137,0.50)" strokeWidth="1"/>
                <path d="M20 1.5L26 5L20 8.5" stroke="rgba(23,126,137,0.70)" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

// ── Main component ────────────────────────────────────────────

export default function LensShowcase() {
  const [provider, setProvider]       = useState('local');
  const [apiKey, setApiKey]           = useState('');
  const [ollamaUrl]                   = useState('http://localhost:11434');
  const [repoUrl, setRepoUrl]         = useState('');
  const [indexEvents, setIndexEvents] = useState([]);
  const [indexing, setIndexing]       = useState(false);
  const [collection, setCollection]   = useState('');
  const [collections, setCollections] = useState([]);
  const [repoMap, setRepoMap]         = useState(loadRepoMap);

  const [query,       setQuery]       = useState('');
  const [langFilter,  setLangFilter]  = useState('');
  const [searching,   setSearching]   = useState(false);
  const [results,     setResults]     = useState([]);
  const [searchErr,   setSearchErr]   = useState('');
  const [searchTime,  setSearchTime]  = useState(null);
  const [expanded,    setExpanded]    = useState(null);
  const [activeQuery, setActiveQuery] = useState('');
  const [placeholder, setPlaceholder] = useState('');

  const hasAutoSearched = useRef(false);

  // Typewriter placeholder
  const PLACEHOLDERS = [
    'where is authentication handled…',
    'find the rate limiting logic…',
    'how are embeddings generated…',
    'where are API routes defined…',
    'find error handling middleware…',
    'where is caching configured…',
  ];
  useEffect(() => {
    let charIdx = 0, phIdx = 0, erasing = false, timer;
    function tick() {
      const target = PLACEHOLDERS[phIdx];
      if (!erasing) {
        charIdx++;
        setPlaceholder(target.slice(0, charIdx));
        if (charIdx === target.length) { erasing = true; timer = setTimeout(tick, 1800); return; }
      } else {
        charIdx--;
        setPlaceholder(target.slice(0, charIdx));
        if (charIdx === 0) { erasing = false; phIdx = (phIdx + 1) % PLACEHOLDERS.length; timer = setTimeout(tick, 300); return; }
      }
      timer = setTimeout(tick, erasing ? 28 : 52);
    }
    timer = setTimeout(tick, 1000);
    return () => clearTimeout(timer);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const runSearchWith = useCallback(async (q, col) => {
    if (!q.trim() || !col) return;
    setSearching(true);
    setSearchErr('');
    setResults([]);
    setActiveQuery(q);
    const t0 = performance.now();
    try {
      const r = await fetch(`${API}/search`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          query: q.trim(),
          collection: col,
          provider,
          ...(provider === 'openai' && apiKey ? { api_key: apiKey } : {}),
          ...(provider === 'ollama' ? { ollama_url: ollamaUrl } : {}),
          top_k: 8,
          ...(langFilter ? { language: langFilter } : {}),
        }),
      });
      const d = await r.json();
      if (!r.ok) { setSearchErr(d.detail ?? 'Search failed'); return; }
      setResults(d.results ?? []);
      setSearchTime(Math.round(performance.now() - t0));
    } catch (e) {
      setSearchErr(e.message);
    } finally {
      setSearching(false);
    }
  }, [provider, apiKey, ollamaUrl, langFilter]);

  const runSearch = useCallback(() => runSearchWith(query, collection), [runSearchWith, query, collection]);

  const loadCollections = useCallback(async () => {
    if (!API) return;
    try {
      const r = await fetch(`${API}/collections`);
      const d = await r.json();
      const cols = d.collections ?? [];
      setCollections(cols);

      // Prefer the lens-api collection for the demo
      const preferred = cols.find(c => c.includes('lens-api')) || cols[0] || '';
      setCollection(prev => {
        const chosen = prev || preferred;
        // Auto-search once on first load
        if (!hasAutoSearched.current && chosen) {
          hasAutoSearched.current = true;
          setTimeout(() => runSearchWith('where is rate limiting implemented', chosen), 300);
        }
        return chosen;
      });
    } catch {}
  }, [runSearchWith]);

  useEffect(() => { loadCollections(); }, [loadCollections]);

  function handleSampleQuery(q) {
    setQuery(q);
    runSearchWith(q, collection);
  }

  const lastEvent  = indexEvents[indexEvents.length - 1];
  const indexDone  = lastEvent?.type === 'done';
  const activeRepo = repoMap[collection] || '';

  function startIndexPost() {
    if (!repoUrl.trim() || indexing) return;
    if (!API) { setIndexEvents([{ type: 'error', message: 'Lens API URL is not configured.' }]); return; }
    setIndexing(true);
    setIndexEvents([]);
    setResults([]);
    const body = {
      repo_url: repoUrl.trim(),
      provider,
      ...(provider === 'openai' && apiKey ? { api_key: apiKey } : {}),
      ...(provider === 'ollama' ? { ollama_url: ollamaUrl } : {}),
    };
    fetch(`${API}/index`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) })
      .then(async resp => {
        if (!resp.ok) { const t = await resp.text(); setIndexEvents([{ type: 'error', message: `Server error ${resp.status}: ${t.slice(0, 200)}` }]); return; }
        const reader = resp.body.getReader();
        const dec    = new TextDecoder();
        let buf = '';
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          buf += dec.decode(value, { stream: true });
          const lines = buf.split('\n');
          buf = lines.pop() ?? '';
          for (const line of lines) {
            if (!line.startsWith('data:')) continue;
            try {
              const data = JSON.parse(line.slice(5).trim());
              setIndexEvents(prev => [...prev, data]);
              if (data.type === 'done') {
                setCollection(data.collection);
                const updated = { ...loadRepoMap(), [data.collection]: repoUrl.trim() };
                saveRepoMap(updated);
                setRepoMap(updated);
                loadCollections();
              }
            } catch {}
          }
        }
      })
      .catch(err => setIndexEvents(prev => [...prev, { type: 'error', message: err.message }]))
      .finally(() => setIndexing(false));
  }

  async function deleteCollection(name) {
    try {
      await fetch(`${API}/collections/${name}`, { method: 'DELETE' });
      const updated = { ...repoMap };
      delete updated[name];
      saveRepoMap(updated);
      setRepoMap(updated);
      setCollection('');
      setResults([]);
      loadCollections();
    } catch {}
  }

  return (
    <div className="lens-root">
      {expanded && <ResultModal result={expanded} repoUrl={activeRepo} onClose={() => setExpanded(null)} />}

      {/* Background embedding-space graph */}
      <svg className="lens-graph-bg" viewBox="0 0 100 100" preserveAspectRatio="xMidYMid slice" aria-hidden="true">
        <g opacity="0.55">
          {GRAPH_EDGES.map(([a, b], i) => (
            <line key={i} x1={GRAPH_NODES[a].x} y1={GRAPH_NODES[a].y} x2={GRAPH_NODES[b].x} y2={GRAPH_NODES[b].y} stroke="rgba(23,126,137,0.18)" strokeWidth="0.18" />
          ))}
          {GRAPH_NODES.map((n, i) => (
            <circle key={i} cx={n.x} cy={n.y} r={n.r} fill="rgba(23,126,137,0.45)" />
          ))}
        </g>
      </svg>

      <div className="lens-inner">

        {/* ── HERO ── */}
        <header className="lens-hero">
          <div className="lens-logo-row">
            <svg className="lens-logomark" viewBox="0 0 22 22" fill="none" aria-hidden="true">
              <circle cx="11" cy="11" r="9"   stroke="currentColor" strokeWidth="1.6"/>
              <circle cx="11" cy="11" r="4.5" stroke="currentColor" strokeWidth="1.3"/>
              <circle cx="11" cy="11" r="1.5" fill="currentColor"/>
              <line x1="18.5" y1="18.5" x2="21" y2="21" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"/>
            </svg>
            <span className="lens-wordmark">LENS</span>
            <span className="lens-hero-live"><span className="lens-live-dot" />live</span>
          </div>

          <h1 className="lens-hero-headline">
            Search any codebase<br/>in plain English.
          </h1>
          <p className="lens-hero-sub">
            Index a GitHub repo. Ask a question in natural language. Get back exact file paths,
            line numbers, symbol names, and relevance scores — in under a second.
          </p>

          <Pipeline />
        </header>

        {/* ── LIVE DEMO ── */}
        <section className="lens-demo-section">
          <div className="lens-demo-eyebrow">
            <span className="lens-demo-badge">Live Demo</span>
            {collection && (
              <span className="lens-demo-repo">
                {activeRepo ? activeRepo.replace('https://github.com/', '') : collection.replace(/^lens-/, '')}
              </span>
            )}
          </div>

          {/* Sample query chips */}
          <div className="lens-sample-queries">
            {SAMPLE_QUERIES.map(q => (
              <button
                key={q}
                className={`lens-sample-chip${activeQuery === q ? ' active' : ''}`}
                onClick={() => handleSampleQuery(q)}
                disabled={searching}
              >
                {q}
              </button>
            ))}
          </div>

          {/* Search bar */}
          <div className="lens-search-row">
            <div className="lens-search-input-wrap">
              <svg className="lens-search-icon" viewBox="0 0 16 16" fill="none" aria-hidden="true">
                <circle cx="6.5" cy="6.5" r="5" stroke="currentColor" strokeWidth="1.4"/>
                <line x1="10.5" y1="10.5" x2="14" y2="14" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
              </svg>
              <input
                className="lens-input lens-search-input"
                placeholder={query ? '' : placeholder || 'search the codebase in plain English…'}
                value={query}
                onChange={e => setQuery(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && runSearch()}
                autoFocus
              />
            </div>
            <LangSelect value={langFilter} onChange={setLangFilter} />
            <button className="lens-btn lens-btn-primary" onClick={runSearch} disabled={searching || !query.trim()}>
              {searching ? <><div className="lens-btn-spinner" />Searching</> : 'Search'}
            </button>
          </div>

          {searchErr && <div className="lens-error-banner" style={{ marginTop: 12 }}>✕ {searchErr}</div>}

          {/* Results */}
          {(results.length > 0 || searching) && (
            <div className="lens-results-wrap">
              {results.length > 0 && (
                <>
                  <div className="lens-results-header">
                    <span>{results.length} results</span>
                    {activeQuery && <span className="lens-results-query">"{activeQuery}"</span>}
                    {searchTime !== null && <span className="lens-latency">{searchTime}ms</span>}
                    {activeRepo && (
                      <a href={activeRepo} target="_blank" rel="noopener noreferrer" className="lens-repo-link">
                        {activeRepo.replace('https://github.com/', '')} ↗
                      </a>
                    )}
                  </div>
                  <div className="lens-results">
                    {results.map((r, i) => (
                      <ResultCard key={i} result={r} index={i} repoUrl={activeRepo} onExpand={setExpanded} />
                    ))}
                  </div>
                </>
              )}
              {searching && (
                <div className="lens-searching-state">
                  <div className="lens-spinner" />
                  <span>Searching vector space…</span>
                </div>
              )}
            </div>
          )}

          {!searching && results.length === 0 && query && !searchErr && (
            <div className="lens-muted" style={{ marginTop: 20, textAlign: 'center' }}>
              No results — try rephrasing or index the repository first.
            </div>
          )}
        </section>

        {/* ── DIVIDER ── */}
        <div className="lens-section-divider">
          <span className="lens-section-divider-label">Configure</span>
        </div>

        {/* ── EMBEDDING MODEL ── */}
        <div className="lens-card">
          <div className="lens-card-title">Embedding Model</div>
          <ModelSelector selected={provider} onChange={setProvider} />
          {provider === 'openai' && (
            <div className="lens-api-key-row">
              <input className="lens-input" type="password" placeholder="sk-…  OpenAI API key" value={apiKey} onChange={e => setApiKey(e.target.value)} />
            </div>
          )}
          {provider === 'ollama' && (
            <div className="lens-info-banner" style={{ marginTop: 14 }}>
              ⚠ Ollama connects from the backend container, not your browser. Use <strong>MiniLM</strong> or <strong>OpenAI</strong> for this hosted demo.
            </div>
          )}
        </div>

        {/* ── INDEX A REPO ── */}
        <div className="lens-card">
          <div className="lens-card-title">Index a Repository</div>
          <div className="lens-demo-repo-chips">
            {DEMO_REPOS.map(d => (
              <button key={d.url} className={`lens-collection-chip${repoUrl === d.url ? ' active' : ''}`} onClick={() => setRepoUrl(d.url)}>
                {d.label}
              </button>
            ))}
          </div>
          <div className="lens-repo-row">
            <input
              className="lens-input"
              placeholder="https://github.com/owner/repo"
              value={repoUrl}
              onChange={e => setRepoUrl(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && startIndexPost()}
            />
            <button className="lens-btn lens-btn-primary" onClick={startIndexPost} disabled={indexing || !repoUrl.trim()}>
              {indexing ? 'Indexing…' : 'Index'}
            </button>
          </div>
          <ProgressView events={indexEvents} />
        </div>

        {/* ── INDEXED COLLECTIONS ── */}
        {collections.length > 0 && (
          <div className="lens-card">
            <div className="lens-card-title">Indexed Repositories</div>
            <div className="lens-collections">
              {collections.map(c => (
                <div key={c} className="lens-chip-row">
                  <button
                    className={`lens-collection-chip${collection === c ? ' active' : ''}`}
                    onClick={() => { setCollection(c); setResults([]); setActiveQuery(''); }}
                  >
                    {repoMap[c] ? repoMap[c].replace('https://github.com/', '') : c.replace(/^lens-/, '')}
                  </button>
                  <button className="lens-delete-btn" title="Delete" onClick={() => deleteCollection(c)}>✕</button>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
}
